UPDATE spells SET summary = 'Move across any liquid surface as solid ground. Up to 10 willing creatures gain this ability. Creatures submerged rise at 60 feet/round.' WHERE slug = 'water-walk';
UPDATE spells SET summary = 'Purifying 30-foot aura centered on you. Nonhostile creatures can''t become diseased, gain poison resistance, and advantage on saves vs. {@condition blinded}, {@condition charmed}, {@condition deafened}, {@condition frightened}, {@condition paralyzed}, {@condition poisoned}, {@condition stunned}.' WHERE slug = 'aura-of-purity';
UPDATE spells SET summary = 'Target creature makes Wisdom save (advantage if fighting you). Fails = {@condition charmed} by you, friendly to you, until spell ends or you harm it. Knows it was charmed when spell ends.' WHERE slug = 'charm-monster';
UPDATE spells SET summary = 'Choose creature and damage type (acid, cold, fire, lightning, thunder). Constitution save or affected for duration. First damage of chosen type each turn deals extra {@damage 2d6} damage. Target loses resistance to that type.' WHERE slug = 'elemental-bane';
UPDATE spells SET summary = 'Ebony tentacles fill 20-foot square, create difficult terrain. Creatures entering/starting turn take {@damage 3d6} bludgeoning, {@condition restrained}. Already restrained take {@damage 3d6} at start of turn. Escape with Str/Dex check.' WHERE slug = 'evard''s-black-tentacles';
UPDATE spells SET summary = 'Touch willing creature. Movement unaffected by difficult terrain, unaffected by magical speed reduction/paralysis/restraint. Spend 5 feet to escape nonmagical restraints. No underwater movement penalties.' WHERE slug = 'freedom-of-movement';
UPDATE spells SET summary = 'Hail of ice pounds 20-foot-radius, 40-foot-high cylinder. Dex save: {@damage 2d8} bludgeoning + {@damage 4d6} cold or half. Area becomes difficult terrain until end of next turn.' WHERE slug = 'ice-storm';
UPDATE spells SET summary = 'Hide chest on Ethereal Plane (12 cu ft). Use action + touch replica to recall/resend. After 60 days, cumulative 5% daily chance effect ends. Ends if replica destroyed or you dismiss it.' WHERE slug = 'leomund''s-secret-chest';
UPDATE spells SET summary = 'Conjure invisible phantom watchdog within 100 feet. Barks loudly if Small+ creatures approach without password. Bites one hostile creature within 5 feet each turn: {@damage 4d8} piercing. Dismissible as action.' WHERE slug = 'mordenkainen''s-faithful-hound';
UPDATE spells SET summary = 'Cube 5-400 feet per side blocks sound, vision/darkvision, divination sensors, teleportation, planar travel. You choose which protections activate. Cast daily for year = permanent.' WHERE slug = 'mordenkainen''s-private-sanctum';
UPDATE spells SET summary = 'Shimmering sphere encloses Large+ creature/object. Unwilling make Dex save. Nothing passes barrier in/out, creatures breathe inside. Weightless sphere, can be rolled/moved. {@spell disintegrate} destroys it.' WHERE slug = 'otiluke''s-resilient-sphere';
UPDATE spells SET summary = 'Create terror illusion in creature''s mind. Wisdom save or {@condition frightened} for duration. End each turn make Wisdom save or take {@damage 4d10} psychic damage.' WHERE slug = 'phantasmal-killer';
UPDATE spells SET summary = 'Dim greenish 30-foot-radius sphere. Creatures entering/starting turn Con save or take {@damage 4d10} radiant + one level {@condition exhaustion}, emit dim light, can''t be {@condition invisible}.' WHERE slug = 'sickening-radiance';
UPDATE spells SET summary = 'Touch Medium stone/section. Shape into any form (weapon, idol, door, passage). Up to 5 feet thick, up to two hinges and latch. No fine mechanical detail.' WHERE slug = 'stone-shape';
UPDATE spells SET summary = '20-foot-radius whirling sphere. Creatures inside/ending turn Str save or {@damage 2d6} bludgeoning, difficult terrain. Bonus action: lightning bolt to 60 feet (advantage if target inside): {@damage 4d6} lightning.' WHERE slug = 'storm-sphere';
UPDATE spells SET summary = 'Summon aberrant spirit: Beholderkin, Slaad, or Star Spawn. Ally, shares initiative, obeys commands. Disappeared if reduced to 0 HP or spell ends. Higher slots use higher stat level.' WHERE slug = 'summon-aberration';
UPDATE spells SET summary = 'Summon construct spirit: Clay, Metal, or Stone. Resembles golem/modron. Ally, shares initiative, obeys commands. Disappears if reduced to 0 HP or spell ends.' WHERE slug = 'summon-construct';
UPDATE spells SET summary = 'Summon elemental spirit: Air, Earth, Fire, or Water. Bipedal form wreathed in element. Ally, shares initiative, obeys commands. Disappears if reduced to 0 HP or spell ends.' WHERE slug = 'summon-elemental';
UPDATE spells SET summary = '1-foot glowing emerald sphere streaks to point, explodes in 20-foot radius. Dex save: {@damage 10d4} acid or half. Failed save = {@damage 5d4} acid at end of next turn.' WHERE slug = 'vitriolic-sphere';
UPDATE spells SET summary = 'Create wall of fire up to 60 feet long/20 feet high/1 foot thick (or 20-foot-diameter ring). One side deals {@damage 5d8} fire to creatures ending turn within 10 feet or inside.' WHERE slug = 'wall-of-fire';
UPDATE spells SET summary = 'Shimmering 10-foot barrier centered on you, moves with you. Blocks creatures except undead/constructs. Ranged/reach attacks through barrier allowed. Spell ends if you move forced creature through.' WHERE slug = 'antilife-shell';
UPDATE spells SET summary = 'Touch Huge+ beast/plant (Int 0-3). Gain Int 10, speak one language, move (if plant). {@condition charmed} by you 30 days or until harmed. Chooses friendliness when charm ends.' WHERE slug = 'awaken';
UPDATE spells SET summary = 'Next weapon hit before spell ends deals {@damage 5d10} extra force damage. If target reduced to 50 HP or fewer, banish it. {@condition incapacitated} in demiplane until spell ends, reappears in original space.' WHERE slug = 'banishing-smite';
UPDATE spells SET summary = 'Create Large translucent hand (AC 20, your max HP). Moves at command. Clenched Fist: {@damage 4d8} force. Forceful Hand: push up to 5+ability feet. Grasping Hand: grapple, crush {@damage 2d6}+ability. Interposing Hand: half cover.' WHERE slug = 'bigby''s-hand';
UPDATE spells SET summary = 'Divine 30-foot aura. Friendly creatures gain advantage on saves vs. spells/magical effects. If save allows half damage, successful save = no damage instead.' WHERE slug = 'circle-of-power';
UPDATE spells SET summary = 'Yellow-green poisonous 20-foot-radius sphere. Creatures entering/starting turn Con save or {@damage 5d8} poison or half. Fog heavily obscures vision, moves 10 feet from you each turn.' WHERE slug = 'cloudkill';
UPDATE spells SET summary = 'Contact deity/proxy, ask up to 3 yes/no questions. Receive correct answers (unclear possible). Casting twice before long rest = cumulative 25% chance per cast to get no answer.' WHERE slug = 'commune';
UPDATE spells SET summary = 'Gain knowledge 3 miles outdoors (300 feet underground). Learn three facts about terrain, creatures, undead, planar influence, buildings in area.' WHERE slug = 'commune-with-nature';
UPDATE spells SET summary = 'Blast of cold from hands in 60-foot cone. Con save: {@damage 8d8} cold or half. Creatures killed become frozen statues until thawed.' WHERE slug = 'cone-of-cold';
UPDATE spells SET summary = 'Fire nonmagical ammo/weapon into air. Duplicates fall in 40-foot-radius, 20-foot-high cylinder. Dex save: {@damage 8d8} damage type of ammo/weapon or half.' WHERE slug = 'conjure-volley';
